import { Avatar, Button, Card, CardActionArea, CardContent, CardHeader, Divider, IconButton, Link, Typography } from '@material-ui/core'
import { More, MoreVert } from '@material-ui/icons'
import { makeStyles } from '@material-ui/styles'
import React from 'react'

const useStyle = makeStyles(theme => {
  return {
    root: {
      // '& .MuiCard-root:hover': {
      // boxShadow: 'none',
      // background: 'none'
    },
    avatar: {
      background: '#162276',
      width: theme.spacing(7),
      height: theme.spacing(7),
    }

  }
})

export default function SubjectCards({ subject }) {
  const classes = useStyle()
  return (
    <div>
      <Card elevation={1}>
          <CardHeader
            avatar={
              <Avatar className={classes.avatar} sizes='medium'>
                P
              </Avatar>
            }
            action= {
              <IconButton>
                <MoreVert />
              </IconButton>
            }

            title={subject.title}
            subheader={subject.instructor}
          />

          <Divider />
          <CardContent>
            <Typography>
              {subject.body}
            </Typography>
          </CardContent>
          <CardActionArea>
            lkjasdlkajsd
          </CardActionArea>
      </Card>
    </div>
  )
}
